mapper.sql:
from aiw_data_source s
where 1 = 1

    and (
        s.source_code like concat('%', #{criteria.keyword}, '%')
        or s.source_name like concat('%', #{criteria.keyword}, '%')
    )


    and s.source_type = #{criteria.sourceType}


    and s.trust_level = #{criteria.trustLevel}


    and s.enabled = #{criteria.enabled}

mapper.select:
select * from aiw_data_source
where source_code = #{sourceCode}
limit 1

select * from aiw_data_source_health
where source_code = #{sourceCode}
limit 1

select * from aiw_data_quality_snapshot
where source_code = #{sourceCode}

    and data_type = #{dataType}

order by snapshot_time desc
limit #{limit}

select s.* 
order by ${sortColumn}

    asc
    desc

limit #{offset}, #{criteria.size}
